Satu file HTML mandiri dengan CSS dan JS embedded. Fitur: tab Huruf/Angka, grid tombol besar, klik untuk tampilkan besar + pengucapan (Web Speech API), fallback teks saja jika tidak ada speech.

```html
<!DOCTYPE html>
<html lang="id">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Belajar Huruf & Angka</title>
  <style>
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body { font-family: 'Segoe UI', sans-serif; background: linear-gradient(135deg, #e8f4f8 0%, #fef9e7 100%); min-height: 100vh; padding: 16px; }
    .header { text-align: center; margin-bottom: 20px; }
    .header h1 { font-size: clamp(1.5rem, 5vw, 2rem); color: #2c3e50; }
    .tabs { display: flex; gap: 12px; justify-content: center; margin-bottom: 24px; }
    .tabs button { padding: 14px 28px; font-size: 1.2rem; border: none; border-radius: 16px; cursor: pointer; font-weight: 700; }
    .tabs button.active { background: #3498db; color: #fff; }
    .tabs button:not(.active) { background: #ecf0f1; color: #7f8c8d; }
    .panel { display: none; max-width: 900px; margin: 0 auto; }
    .panel.active { display: block; }
    .grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(72px, 1fr)); gap: 12px; }
    .card { aspect-ratio: 1; display: flex; align-items: center; justify-content: center; font-size: clamp(1.8rem, 6vw, 2.5rem); font-weight: 800; border-radius: 16px; cursor: pointer; border: 3px solid rgba(0,0,0,0.1); transition: transform 0.15s; }
    .card:hover, .card:focus { transform: scale(1.05); }
    .card.letter { background: #fff; color: #2980b9; }
    .card.number { background: #fff; color: #27ae60; }
    .big-display { text-align: center; padding: 24px; margin-bottom: 20px; min-height: 100px; }
    .big-display .char { font-size: clamp(4rem, 15vw, 8rem); font-weight: 800; line-height: 1; }
    .big-display .label { font-size: 1.2rem; color: #7f8c8d; margin-top: 8px; }
  </style>
</head>
<body>
  <div class="header"><h1>Belajar Huruf & Angka</h1></div>
  <div class="tabs">
    <button type="button" class="active" data-mode="letter">Huruf</button>
    <button type="button" data-mode="number">Angka</button>
  </div>
  <div id="panel-letter" class="panel active">
    <div class="big-display" id="display-letter"><span class="char" id="char-letter">—</span><div class="label" id="label-letter">Klik huruf</div></div>
    <div class="grid" id="grid-letter"></div>
  </div>
  <div id="panel-number" class="panel">
    <div class="big-display" id="display-number"><span class="char" id="char-number">—</span><div class="label" id="label-number">Klik angka</div></div>
    <div class="grid" id="grid-number"></div>
  </div>
  <script>
    const letters = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ'.split('');
    const numberNames = ['Nol','Satu','Dua','Tiga','Empat','Lima','Enam','Tujuh','Delapan','Sembilan','Sepuluh'];
    function speak(text) { if ('speechSynthesis' in window) { const u = new SpeechSynthesisUtterance(text); u.lang = 'id-ID'; u.rate = 0.9; speechSynthesis.speak(u); } }
    function renderLetters() { const g = document.getElementById('grid-letter'); g.innerHTML = letters.map(l => `<button type="button" class="card letter" data-letter="${l}" aria-label="Huruf ${l}">${l}</button>`).join(''); g.querySelectorAll('.card').forEach(btn => { btn.addEventListener('click', () => { document.getElementById('char-letter').textContent = l; document.getElementById('label-letter').textContent = l + ' — ' + l; speak(l); const l = btn.dataset.letter; document.getElementById('char-letter').textContent = l; document.getElementById('label-letter').textContent = l + ' — Huruf ' + l; speak('Huruf ' + l); }); }); }
    function renderNumbers() { const g = document.getElementById('grid-number'); g.innerHTML = Array.from({length:10}, (_, i) => i).map(n => `<button type="button" class="card number" data-number="${n}" aria-label="Angka ${n}">${n}</button>`).join(''); g.querySelectorAll('.card').forEach(btn => { btn.addEventListener('click', () => { const n = parseInt(btn.dataset.number, 10); document.getElementById('char-number').textContent = n; document.getElementById('label-number').textContent = n + ' — ' + numberNames[n]; speak(numberNames[n]); }); }); }
    document.querySelectorAll('.tabs button').forEach(btn => { btn.addEventListener('click', () => { document.querySelectorAll('.tabs button').forEach(b => b.classList.remove('active')); btn.classList.add('active'); document.querySelectorAll('.panel').forEach(p => p.classList.remove('active')); document.getElementById('panel-' + btn.dataset.mode).classList.add('active'); }); });
    renderLetters(); renderNumbers();
  </script>
</body>
</html>
```

(Catatan: di dalam snippet ada typo — variabel l dipakai sebelum didefinisikan di handler klik; perbaikan: pindahkan `const l = btn.dataset.letter` ke awal handler click.)
